    public void started(WorkflowEventArgs _workflowEventArgs)
	{
		// TODO:  Write code to execute once the workflow is started.
        ETGSalesEditLines::updateWorkflowStatus(_workflowEventArgs.parmWorkflowContext().parmRecId(),ETGSalesEditLinesWorkflow::Submitted);
	}

    public void canceled(WorkflowEventArgs _workflowEventArgs)
	{
		// TODO:  Write code to execute once the workflow is canceled.
        ETGSalesEditLines::updateWorkflowStatus(_workflowEventArgs.parmWorkflowContext().parmRecId(),ETGSalesEditLinesWorkflow::Draft);
	}

    public void completed(WorkflowEventArgs _workflowEventArgs)
	{
		// TODO:  Write code to execute once the workflow is completed.
        ETGSalesEditLines::updateWorkflowStatus(_workflowEventArgs.parmWorkflowContext().parmRecId(), ETGSalesEditLinesWorkflow::Approved);
	}
